module top_module(
  input clk,
  input [31:0] addr, writeData,
  input memWrite, memRead,
  output [31:0] readData
);reg [31:0] mem [0:255];  

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin 
    if(memWrite)
      mem[addr] <= writeData;
  end

  assign readData = memRead ? mem[addr] : 0;
endmodule
